VALUES
  ('locality-e3452428-moex-00114', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '甲公立學校錄取公費生乙，甲與乙書面約定，乙若違約，甲得逕依約強制執行。乙就讀一學期後 遭受退學，預估應賠償甲新臺幣5萬元，下列敘述何者錯誤？', '["甲與乙之書面約定性質為行政契約", "如生契約爭議，甲應向高等行政法院地方行政訴訟庭起訴", "甲得依約自行逕行行政強制執行", "甲起訴時應繳納裁判費新臺幣2千元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00115', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於行政指導，下列敘述何者正確？', '["行政指導應符合授權明確性原則", "行政指導屬於行政契約之一種類型", "行政指導之拒絕，相對人須以書面為之", "行政指導仍有法律優位原則之適用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00116', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於行政罰之敘述，下列何者錯誤？', '["一行為違反數個行政法上義務規定且均應處罰鍰時，其罰鍰之金額應依法定罰鍰額最高之規定 裁處，但不得低於各該規定之罰鍰最低額", "違反行政法上義務之處罰，以行為時之法律或自治條例有明文規定者為限", "公立醫院違反廢棄物清理法之行政法上義務，因其屬於公權力主體，主管機關不得裁罰之", "被主管機關接管中之保險公司，仍得作為裁罰之對象"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00117', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '某市政府發現民眾甲屋庭院內之樹木，即將傾倒危及民眾，乃直接僱工進入甲屋庭院，鋸倒該樹 木，此行為之法律性質為何？', '["間接強制中之代履行", "行政義務之直接強制", "即時強制", "定暫時狀態之處分 30840、31140 31640、31740 31940"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00118', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '甲向建管機關A申請核發建築執照，但因資料不全經A通知補件；為補齊申請資料，甲遂依行 政程序法向A申請閱覽卷宗，但遭A拒絕，嗣A駁回甲之建照申請。關於甲救濟之敘述，下列 何者正確？', '["得分別針對拒絕閱覽卷宗與駁回建照之決定提起救濟", "僅能針對駁回建照之決定請求救濟，行政機關拒絕閱覽卷宗之決定無法救濟", "對於駁回建照之決定請求救濟之同時，一併對拒絕閱覽卷宗之決定表示不服", "對於拒絕閱覽卷宗與駁回建照之決定皆無法提起救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00119', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於訴願機關審查範圍之敘述，下列何者正確？', '["訴願機關原則上僅得審查行政處分之合法性", "訴願機關審查大學對大學生所為與講學有關之行政處分，應適度尊重大學之專業判斷", "訴願機關得就地方自治團體辦理自治事項所為行政處分之合目的性進行審查", "訴願機關得以自己之判斷取代考試評分事件中原處分機關之判斷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00120', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於訴願管轄之敘述，下列何者正確？', '["不服公平交易委員會之行政處分者，應以行政院為訴願管轄機關", "汽車燃料使用費之徵收，應以交通部為訴願管轄機關", "同一直轄市主管之數個高級中學成立聯合甄審委員會，對於教師新聘事項進行評審，以教育部 為訴願管轄機關", "有關國民年金保險事項所為之核定，以勞動部勞工保險局為訴願管轄機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00121', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '依最新司法實務見解，A大學對所屬教師不予續聘決定，教師不服而提起申訴，經申訴評議決定 駁回後，教師復向教育部中央教師申訴評議委員會提起再申訴，再申訴決定撤銷大學不予續聘決 定，A大學得否就再申訴決定提起行政訴訟？', '["無論公立或私立大學均不得提起行政訴訟", "無論公立或私立大學均得提起行政訴訟", "若該大學係屬公立大學，則不得提起行政訴訟；若屬私立大學，則得提起行政訴訟", "若該大學係屬私立大學，則不得提起行政訴訟；若屬公立大學，則得提起行政訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00122', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '甲原經乙市政府社會局核定為低收入戶並按月領有低收入生活扶助，嗣後社會局查知甲已將戶籍 遷出乙市，乃以A函通知甲自即日起廢止其低收入戶資格並停止發給生活扶助。甲不服，循序提 起訴願及撤銷訴訟，經行政法院撤銷A函，但社會局僅繼續發給確定判決後之生活扶助。甲依法 應如何救濟？', '["提起再審", "提起課予義務訴訟", "請求行政訴訟強制執行", "提起一般給付訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00123', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於行政裁量之敘述，下列何者錯誤？', '["法院在認定裁量怠惰時，應視該被指摘漏未考量之因素在個案中之權重，而為決定", "行政機關為裁量時，若違反平等原則，即構成裁量瑕疵", "行政機關以狀態責任人為裁罰對象時，應斟酌其有無事實支配管領力、能否有效為停止使用等 情事", "行政機關於個案行使裁量權時，作成不同於裁量基準之決定，即構成裁量濫用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL)
